Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "data": { "name": "dataset" },

  "transform": [
    /* Min/Max for contrast; denominator as constant per row */
    {
      "joinaggregate": [
        { "op": "min", "field": "Total Measurements Recorded", "as": "MinVal" },
        { "op": "max", "field": "Total Measurements Recorded", "as": "MaxVal" },
        { "op": "max", "field": "Total Measurements Remove Filters", "as": "OverallExcluded" }
      ]
    },

    /* Percent of the fixed denominator (safe if denominator is 0) */
    {
      "calculate": "datum.OverallExcluded > 0 ? datum[''Total Measurements Recorded''] / datum.OverallExcluded : null",
      "as": "PctOfExcluded"
    },

    /* Normalize value 0..1 for dark/light text switching */
    {
      "calculate": "datum.MaxVal > datum.MinVal ? (datum[''Total Measurements Recorded''] - datum.MinVal) / (datum.MaxVal - datum.MinVal) : 0",
      "as": "Norm"
    },

    /* Flag for whether this cell has a real count > 0 */
    {
      "calculate": "isValid(datum[''Total Measurements Recorded'']) && datum[''Total Measurements Recorded''] > 0",
      "as": "HasValue"
    },

    /* Build labels only when HasValue; otherwise empty strings */
    {
      "calculate": "datum.HasValue ? format(datum[''Total Measurements Recorded''], '','') : ''''",
      "as": "ValueLabel"
    },
    {
      "calculate": "datum.HasValue && isValid(datum.PctOfExcluded) ? '' ('' + format(datum.PctOfExcluded, ''.1%'') + '')'' : ''''",
      "as": "PctLabel"
    }
  ],

  "encoding": {
    "x": {
      "field": "Criteria End",
      "type": "ordinal",
      "sort": ["Valid", "Invalid", "Missing"],
      "scale": { "domain": { "unionWith": ["Valid", "Invalid", "Missing"] } },
      "axis": {
        "title": "End Score Type",
        "orient": "top",
        "labelAngle": 0,
        "labelFontSize": 9,
        "labelFontWeight": "normal",
        "labelFont": "Calibri",
        "labelColor": "#555555",
        "titleFontSize": 11,
        "titleFontWeight": "bold",
        "titleFont": "Calibri",
        "titleColor": "#555555"
      }
    },
    "y": {
      "field": "Criteria Start",
      "type": "ordinal",
      "sort": ["Valid", "Invalid", "Missing"],
      "scale": { "domain": { "unionWith": ["Valid", "Invalid", "Missing"] } },
      "axis": {
        "title": "Start Score Type",
        "labelFontSize": 9,
        "labelFontWeight": "normal",
        "labelFont": "Calibri",
        "labelColor": "#555555",
        "titleFontSize": 11,
        "titleFontWeight": "bold",
        "titleFont": "Calibri",
        "titleColor": "#555555"
      }
    }
  },

  "layer": [
    /* Heatmap background */
    {
      "name": "cellRect",
      "mark": { "type": "rect", "tooltip": true },
      "encoding": {
        "color": {
          "field": "Total Measurements Recorded",
          "type": "quantitative",
          "scale": { "range": ["#FFCCCC", "#FF9999", "#FF6666", "#FF3333"] },
          "legend": null
        },
        "tooltip": [
          { "field": "Criteria Start", "type": "nominal", "title": "Criteria Start" },
          { "field": "Criteria End", "type": "nominal", "title": "Criteria End" },
          { "field": "Total Measurements Recorded", "type": "quantitative", "title": "Total", "format": "," },
          { "field": "PctOfExcluded", "type": "quantitative", "title": "% of Excluded Other", "format": ".1%" },
          { "field": "OverallExcluded", "type": "quantitative", "title": "Excluded Other (Denominator)", "format": "," }
        ]
      }
    },

    /* Value (left) — only visible if HasValue */
    {
      "mark": {
        "type": "text",
        "align": "center",
        "baseline": "middle",
        "font": "Calibri",
        "fontSize": 10,
        "fontWeight": "bold",
        "dx": -15
      },
      "encoding": {
        "text": { "field": "ValueLabel", "type": "nominal" },
        "opacity": {
          "condition": { "test": "datum.HasValue", "value": 1 },
          "value": 0
        },
        "color": {
          "condition": { "test": "datum.Norm >= 0.6", "value": "white" },
          "value": "black"
        }
      }
    },

    /* Percentage (right) — only visible if HasValue and percent exists */
    {
      "mark": {
        "type": "text",
        "align": "center",
        "baseline": "middle",
        "font": "Calibri",
        "fontSize": 8,
        "fontStyle": "italic",
        "dx": 18
      },
      "encoding": {
        "text": { "field": "PctLabel", "type": "nominal" },
        "opacity": {
          "condition": { "test": "datum.HasValue && length(datum.PctLabel) > 0", "value": 1 },
          "value": 0
        },
        "color": {
          "condition": { "test": "datum.Norm >= 0.6", "value": "white" },
          "value": "#555555"
        }
      }
    }
  ],

  "config": { "view": { "step": 40 } }
}'
